mapper.select:
SELECT d.device_id, d.device_name, g.group_name, latest.soc, CASE WHEN latest.soc IS NULL THEN 'NO_DATA' WHEN latest.soc = 0 THEN 'OFFLINE' WHEN latest.soc < 20 THEN 'ERROR' WHEN latest.soc < 40 THEN 'WARNING' ELSE 'NORMAL' END AS status FROM ess_device d
LEFT JOIN ess_device_group g ON d.group_id = g.group_id
LEFT JOIN ( SELECT device_id, soc FROM ( SELECT device_id, soc, ROW_NUMBER() OVER ( PARTITION BY device_id ORDER BY record_time DESC ) AS rn FROM monitoring WHERE record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND record_time < DATE_ADD( STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY ) ) ranked WHERE rn = 1 ) latest ON d.device_id = latest.device_id
WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
ORDER BY d.device_id ASC

SELECT user_type
FROM ess_member
WHERE member_id = #{memberId}

SELECT IFNULL(g.group_name, '미지정 그룹') AS label, IFNULL( SUM( CASE WHEN m.solar_generation_kwh BETWEEN 0 AND d.capacity_kw * 24 THEN m.solar_generation_kwh END ), 0 ) AS generation FROM ess_device d LEFT JOIN ess_device_group g ON d.group_id = g.group_id LEFT JOIN monitoring m ON d.device_id = m.device_id AND m.record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY) WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
GROUP BY d.group_id, g.group_name ORDER BY generation DESC LIMIT #{limit}

SELECT d.device_name AS label, IFNULL( SUM( CASE WHEN m.solar_generation_kwh BETWEEN 0 AND d.capacity_kw * 24 THEN m.solar_generation_kwh END ), 0 ) AS generation FROM ess_device d LEFT JOIN monitoring m ON d.device_id = m.device_id AND m.record_time >= STR_TO_DATE(#{selectedDate}, '%Y-%m-%d') AND m.record_time < DATE_ADD(STR_TO_DATE(#{selectedDate}, '%Y-%m-%d'), INTERVAL 1 DAY) WHERE d.member_id = #{memberId}
AND d.group_id = #{groupId}
AND d.device_id = #{deviceId}
GROUP BY d.device_id, d.device_name ORDER BY generation DESC LIMIT #{limit}
